import { type ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { Container, SelectList, Text, Spacer } from "@mariozechner/pi-tui";
import { readdir } from "node:fs/promises";
import { resolve, join } from "node:path";
import os from "node:os";

export default function (pi: ExtensionAPI) {
  pi.registerCommand("session-import", {
    description: "Browse and import past sessions",
    handler: async (_, ctx) => {
      const sessionDir = resolve(os.homedir(), ".pi/agent/sessions");

      // Recursively find all .jsonl files
      async function getFiles(dir: string): Promise<string[]> {
        const entries = await readdir(dir, { withFileTypes: true });
        const files = await Promise.all(
          entries.map((res) => {
            const resPath = resolve(dir, res.name);
            return res.isDirectory() ? getFiles(resPath) : (res.name.endsWith(".jsonl") ? resPath : []);
          })
        );
        return files.flat();
      }

      const filePaths = await getFiles(sessionDir);

      if (filePaths.length === 0) {
        ctx.ui.notify("No session files found.", "warning");
        return;
      }

      const items = filePaths.map(path => ({
        value: path,
        label: path.split('/').pop() || path,
        description: path.replace(os.homedir(), "~")
      }));

      const selectedPath = await ctx.ui.custom<string>((tui, theme, _kb, done) => {
        const container = new Container();
        container.addChild(new Text(theme.fg("accent", theme.bold(" Select Session to Import")), 1, 0));
        container.addChild(new Spacer(1));

        const list = new SelectList(items, 15, {
          selectedPrefix: (t) => theme.fg("accent", t),
          selectedText: (t) => theme.fg("accent", t),
          description: (t) => theme.fg("muted", t),
        });

        list.onSelect = (item) => done(item.value);
        list.onCancel = () => done("");
        container.addChild(list);

        return {
          render: (w) => container.render(w),
          invalidate: () => container.invalidate(),
          handleInput: (data) => {
            list.handleInput(data);
            tui.requestRender();
          },
        };
      }, { overlay: true });

      if (selectedPath) {
        // We notify the user of the command to run. 
        // We can't automatically run /import from inside an extension, 
        // but we can provide the exact path which is now on their screen.
        ctx.ui.notify(`Run: /import ${selectedPath}`, "info");
        ctx.ui.setEditorText(`/import ${selectedPath}`);
      }
    },
  });
}

