// Recursively find all .jsonl files with mtime
async function getFiles(dir: string): Promise<{ path: string; mtime: number }[]> {
  const entries = await readdir(dir, { withFileTypes: true });
  const results = await Promise.all(
    entries.map(async (res) => {
      const resPath = resolve(dir, res.name);
      if (res.isDirectory()) {
        return getFiles(resPath);
      } else if (res.name.endsWith(".jsonl")) {
        const stats = await stat(resPath);
        return [{ path: resPath, mtime: stats.mtimeMs }];
      }
      return [];
    })
  );
  return results.flat();
}

